     1→import React, { useEffect, useRef, useState, useCallback } from "react";
     2→import { Terminal } from "@xterm/xterm";
     3→import { FitAddon } from "@xterm/addon-fit";
     4→import { Box, ActionIcon, Text, Group } from "@mantine/core";
     5→import "@xterm/xterm/css/xterm.css";
     6→
     7→interface Props {
     8→  cwd: string;
     9→  /** Initial height in px for the terminal panel (excluding header). */
    10→  defaultHeight?: number;
    11→  /** Command to type into the shell after connection is established. */
    12→  command?: string;
    13→}
    14→
    15→const MIN_HEIGHT = 80;
    16→const HEADER_H = 28;
    17→
    18→export function EmbeddedTerminal({ cwd, defaultHeight = 220, command }: Props) {
    19→  const containerRef = useRef<HTMLDivElement>(null);
    20→  const termRef = useRef<Terminal | null>(null);
    21→  const fitRef = useRef<FitAddon | null>(null);
    22→  const wsRef = useRef<WebSocket | null>(null);
    23→  const [minimized, setMinimized] = useState(false);
    24→  const [height, setHeight] = useState(defaultHeight);
    25→  const dragState = useRef<{ startY: number; startH: number } | null>(null);
    26→
    27→  // ── Terminal lifecycle ──────────────────────────────────────────────────
    28→  useEffect(() => {
    29→    if (!containerRef.current) return;
    30→
    31→    const term = new Terminal({
    32→      fontFamily: 'ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, monospace',
    33→      fontSize: 12,
    34→      lineHeight: 1.4,
    35→      theme: {
    36→        background: "#0d1117",
    37→        foreground: "#e6edf3",
    38→        cursor: "#e6edf3",
    39→        selectionBackground: "#264f78",
    40→        black: "#0d1117",
    41→        red: "#ff7b72",
    42→        green: "#3fb950",
    43→        yellow: "#d29922",
    44→        blue: "#58a6ff",
    45→        magenta: "#bc8cff",
    46→        cyan: "#39d353",
    47→        white: "#b1bac4",
    48→        brightBlack: "#6e7681",
    49→        brightRed: "#ffa198",
    50→        brightGreen: "#56d364",
    51→        brightYellow: "#e3b341",
    52→        brightBlue: "#79c0ff",
    53→        brightMagenta: "#d2a8ff",
    54→        brightCyan: "#56d364",
    55→        brightWhite: "#f0f6fc",
    56→      },
    57→      cursorBlink: true,
    58→      allowProposedApi: true,
    59→    });
    60→
    61→    const fitAddon = new FitAddon();
    62→    term.loadAddon(fitAddon);
    63→    term.open(containerRef.current);
    64→    fitAddon.fit();
    65→    termRef.current = term;
    66→    fitRef.current = fitAddon;
    67→
    68→    const ws = new WebSocket(
    69→      `ws://localhost:3000?type=terminal&cwd=${encodeURIComponent(cwd)}`,
    70→    );
    71→    wsRef.current = ws;
    72→
    73→    ws.onopen = () => {
    74→      const { cols, rows } = term;
    75→      ws.send(JSON.stringify({ type: "resize", cols, rows }));
    76→      if (command) {
    77→        setTimeout(() => {
    78→          ws.send(JSON.stringify({ type: "data", data: command + "\n" }));
    79→        }, 300);
    80→      }
    81→    };
    82→
    83→    ws.onmessage = (e) => {
    84→      try {
    85→        const msg = JSON.parse(e.data as string) as { type: string; data?: string };
    86→        if (msg.type === "data" && msg.data) term.write(msg.data);
    87→      } catch { /* ignore */ }
    88→    };
    89→
    90→    term.onData((data) => {
    91→      if (ws.readyState === WebSocket.OPEN) ws.send(JSON.stringify({ type: "data", data }));
    92→    });
    93→
    94→    term.onResize(({ cols, rows }) => {
    95→      if (ws.readyState === WebSocket.OPEN) ws.send(JSON.stringify({ type: "resize", cols, rows }));
    96→    });
    97→
    98→    return () => {
    99→      term.dispose();
   100→      ws.close();
   101→      termRef.current = null;
   102→      fitRef.current = null;
   103→      wsRef.current = null;
   104→    };
   105→  }, [cwd]);
   106→
   107→  // ── Refit when height changes or terminal is restored ───────────────────
   108→  useEffect(() => {
   109→    if (minimized) return;
   110→    const t = setTimeout(() => fitRef.current?.fit(), 16);
   111→    return () => clearTimeout(t);
   112→  }, [height, minimized]);
   113→
   114→  // ── Resize drag handle ──────────────────────────────────────────────────
   115→  const onDragStart = useCallback((e: React.MouseEvent) => {
   116→    e.preventDefault();
   117→    dragState.current = { startY: e.clientY, startH: height };
   118→
   119→    const onMove = (ev: MouseEvent) => {
   120→      if (!dragState.current) return;
   121→      const delta = dragState.current.startY - ev.clientY; // drag up = bigger terminal
   122→      const next = Math.max(MIN_HEIGHT, dragState.current.startH + delta);
   123→      setHeight(next);
   124→    };
   125→    const onUp = () => {
   126→      dragState.current = null;
   127→      window.removeEventListener("mousemove", onMove);
   128→      window.removeEventListener("mouseup", onUp);
   129→    };
   130→    window.addEventListener("mousemove", onMove);
   131→    window.addEventListener("mouseup", onUp);
   132→  }, [height]);
   133→
   134→  return (
   135→    <Box
   136→      style={{
   137→        display: "flex",
   138→        flexDirection: "column",
   139→        flexShrink: 0,
   140→        borderTop: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
   141→      }}
   142→    >
   143→      {/* Drag handle (above the header) */}
   144→      {!minimized && (
   145→        <Box
   146→          onMouseDown={onDragStart}
   147→          style={{
   148→            height: 4,
   149→            cursor: "ns-resize",
   150→            backgroundColor: "transparent",
   151→            flexShrink: 0,
   152→          }}
   153→          onMouseEnter={(e) => { (e.currentTarget as HTMLElement).style.backgroundColor = "var(--mantine-color-indigo-6)"; }}
   154→          onMouseLeave={(e) => { (e.currentTarget as HTMLElement).style.backgroundColor = "transparent"; }}
   155→        />
   156→      )}
   157→
   158→      {/* Header bar */}
   159→      <Group
   160→        gap={6}
   161→        px={10}
   162→        style={{
   163→          height: HEADER_H,
   164→          flexShrink: 0,
   165→          backgroundColor: "light-dark(var(--mantine-color-gray-1), var(--mantine-color-dark-7))",
   166→          borderTop: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
   167→          cursor: "default",
   168→          userSelect: "none",
   169→        }}
   170→      >
   171→        <Text size="xs" c="dimmed" ff="monospace" style={{ flex: 1 }}>
   172→          ⬡ terminal
   173→        </Text>
   174→        <ActionIcon
   175→          size="xs"
   176→          variant="subtle"
   177→          color="gray"
   178→          title={minimized ? "Expand terminal" : "Minimize terminal"}
   179→          onClick={() => setMinimized((m) => !m)}
   180→        >
   181→          {minimized ? "▲" : "▼"}
   182→        </ActionIcon>
   183→      </Group>
   184→
   185→      {/* xterm container — always mounted so the PTY connection survives minimize */}
   186→      <Box
   187→        style={{
   188→          height: minimized ? 0 : height,
   189→          overflow: "hidden",
   190→          backgroundColor: "#0d1117",
   191→          padding: minimized ? 0 : "4px 4px 4px 2px",
   192→        }}
   193→      >
   194→        <div ref={containerRef} style={{ width: "100%", height: "100%" }} />
   195→      </Box>
   196→    </Box>
   197→  );
   198→}
   199→

