   713→export function SessionDetail() {
   714→  const navigate = useNavigate();
   715→  const { sessionId } = useParams<{ sessionId: string }>();
   716→  const [searchParams] = useSearchParams();
   717→  const location = useLocation();
   718→  const targetLogEventId = searchParams.get("logEventId") ? parseInt(searchParams.get("logEventId")!) : null;
   719→  const searchSnippet = (location.state as { snippet?: string; contentType?: string; hideTerminal?: boolean } | null)?.snippet ?? null;
   720→  const searchContentType = (location.state as { snippet?: string; contentType?: string; hideTerminal?: boolean } | null)?.contentType ?? null;
   721→  const hideTerminal = (location.state as { hideTerminal?: boolean } | null)?.hideTerminal ?? false;
   722→  const [highlightActive, setHighlightActive] = useState(false);
   723→  const scrolledRef = useRef(false);
   724→  const viewportRef = useRef<HTMLDivElement>(null);
   725→  const logEventsRef = useRef<LogEventItem[]>([]);
   726→  const [session, setSession] = useState<Session | null>(null);
   727→  const [checkpoints, setCheckpoints] = useState<SessionCheckpoint[]>([]);
   728→  const [groups, setGroups] = useState<Map<string, RenderItem[]>>(new Map([["shadow", []]]));
   729→  const [selectedId, setSelectedId] = useState<string>("shadow");
   730→  const [latestCheckpoint, setLatestCheckpoint] = useState<SessionCheckpoint | null>(null);
   731→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   732→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   733→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   734→  const [spawning, setSpawning] = useState(false);
   735→  const [loading, setLoading] = useState(true);
   736→  const [error, setError] = useState<string | null>(null);
   737→
   738→  const id = sessionId!;
   739→  const { setCrumbs } = useBreadcrumb();
   740→  const { updateTabTitle } = useTabs();
   741→
   742→  function applyData(logEvs: LogEventItem[], cps: SessionCheckpoint[], autoSelect = false) {
   743→    const sorted = [...cps].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   744→    const latest = sorted[sorted.length - 1] ?? null;
   745→    setLatestCheckpoint(latest);
   746→    setOpenItems(latest?.summary?.openItems ?? []);
   747→    setCheckpoints(sorted);
   748→    const newGroups = buildCheckpointGroups(logEvs, cps);
   749→    setGroups(newGroups);
   750→    if (autoSelect && targetLogEventId !== null) {
   751→      const targetGroup = findGroupForLogEvent(newGroups, targetLogEventId);
   752→      if (targetGroup) setSelectedId(targetGroup);
   753→    }
   754→  }
   755→
   756→  useEffect(() => {
   757→    Promise.all([fetchSession(id), fetchLogEvents(id), fetchSessionCheckpoints(id)])
   758→      .then(([s, logEvs, cps]) => {
   759→        logEventsRef.current = logEvs;
   760→        setSession(s);
   761→        const title = s.summary ?? s.intent ?? s.prompt?.slice(0, 80) ?? s.sessionId.slice(0, 8) + "…";
   762→        updateTabTitle(`session:${s.sessionId}`, title);
   763→        const user = s.gitUserName ?? s.gitUserEmail ?? null;
   764→        const repo = s.repoName ?? null;
   765→        const shortId = s.sessionId.slice(0, 8) + "…";
   766→        if (user) {
   767→          setUserInfo({
   768→            name: s.gitUserName ?? user,
   769→            avatarUrl: s.gitUserName ? `https://github.com/${s.gitUserName}.png?size=40` : undefined,
   770→          });
   771→        }
   772→        setCrumbs([
   773→          ...(user ? [{ label: user, path: "/" }] : []),
   774→          ...(repo ? [{ label: repo, path: "/" }] : []),
   775→          { label: shortId },
   776→        ]);
   777→        applyData(logEvs, cps, true);
   778→        setError(null);
   779→      })
   780→      .catch((err: unknown) => setError(String(err)))
   781→      .finally(() => setLoading(false));
   782→  }, [id]);
   783→
   784→  useEffect(() => {
   785→    return subscribeToUpdates(() => {
   786→      Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
   787→        .then(([logEvs, cps]) => {
   788→          logEventsRef.current = logEvs;
   789→          applyData(logEvs, cps);
   790→        })
   791→        .catch(() => undefined);
   792→    });
   793→  }, [id]);
   794→
   795→  // When the session is live (actively running), poll at 500ms so the UI
   796→  // stays current without waiting for the server's 2s broadcast cycle.
   797→  useEffect(() => {
   798→    if (!session?.isLive) return;
   799→    const timer = setInterval(() => {
   800→      Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
